import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';

const PROTOCOLES = [
  { id: 'rage', label: 'Anti-Rabique Tissulaire' },
  { id: 'hepb', label: 'Hépatite B' },
  { id: 'dt', label: 'Anti-Diphtérique et Antitéitanique (DT)' }
];

const inputStyle = { width: '100%', padding: '12px 16px', borderRadius: '8px', border: '1px solid #eaebef', outline: 'none', fontSize: '14px', background: '#f4f5f9' };
const labelStyle = { fontSize: '12px', fontWeight: 700, color: '#8a94a6', display: 'block', marginBottom: '6px', textTransform: 'uppercase' };

// --- SOUS-FORMULAIRES ---

function ProtocoleRage({ data, set }) {
  const grades = ['Grade I', 'Grade II', 'Grade III'];
  const jours = ['J0', 'J3', 'J7', 'J14', 'J28', 'J90'];

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
        <div>
          <label style={labelStyle}>Date d'exposition *</label>
          <input type="date" value={data.dateExposition || ''} onChange={e => set({ ...data, dateExposition: e.target.value })} style={inputStyle} required />
        </div>
        <div>
          <label style={labelStyle}>Gravité *</label>
          <div style={{ display: 'flex', gap: '8px', marginTop: '4px' }}>
            {grades.map(g => (
              <label key={g} style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '10px', border: data.grade === g ? '2px solid #0056ff' : '1px solid #eaebef', borderRadius: '8px', cursor: 'pointer', background: data.grade === g ? '#ebf2ff' : 'white', color: data.grade === g ? '#0056ff' : '#8a94a6', fontWeight: 700, fontSize: '13px' }}>
                <input type="radio" name="grade" value={g} checked={data.grade === g} onChange={e => set({ ...data, grade: e.target.value })} style={{ display: 'none' }} />
                {g}
              </label>
            ))}
          </div>
        </div>
      </div>

      <div style={{ border: '1px solid #eaebef', borderRadius: '8px', overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'center', fontSize: '13px' }}>
          <thead>
            <tr style={{ background: '#f4f5f9', color: '#1d2129' }}>
              <th style={{ padding: '12px', borderBottom: '1px solid #eaebef', borderRight: '1px solid #eaebef' }}>Jour</th>
              <th style={{ padding: '12px', borderBottom: '1px solid #eaebef', borderRight: '1px solid #eaebef' }}>Date Prévue / Faite</th>
              <th style={{ padding: '12px', borderBottom: '1px solid #eaebef' }}>VAR / SAR+VAR</th>
            </tr>
          </thead>
          <tbody>
            {jours.map((j) => {
              const row = data.doses?.[j] || { date: '', type: 'VAR' };
              return (
                <tr key={j} style={{ borderBottom: '1px solid #eaebef' }}>
                  <td style={{ padding: '10px', borderRight: '1px solid #eaebef', fontWeight: 800 }}>{j}</td>
                  <td style={{ padding: '10px', borderRight: '1px solid #eaebef' }}>
                    <input type="date" value={row.date} onChange={e => set({ ...data, doses: { ...data.doses, [j]: { ...row, date: e.target.value } }})} style={{ padding: '6px 10px', borderRadius: '6px', border: '1px solid #eaebef', width: '100%', boxSizing: 'border-box' }} />
                  </td>
                  <td style={{ padding: '10px' }}>
                    <select value={row.type} onChange={e => set({ ...data, doses: { ...data.doses, [j]: { ...row, type: e.target.value } }})} style={{ padding: '6px 10px', borderRadius: '6px', border: '1px solid #eaebef', width: '100%', boxSizing: 'border-box' }}>
                      <option value="VAR">VAR</option>
                      <option value="SAR+VAR">SAR + VAR</option>
                    </select>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '16px' }}>
        <div>
          <label style={labelStyle}>Observations</label>
          <input value={data.observations || ''} onChange={e => set({ ...data, observations: e.target.value })} placeholder="Voie intramusculaire, remarques..." style={inputStyle} />
        </div>
        <div>
          <label style={labelStyle}>Médecin</label>
          <input value={data.medecin || ''} onChange={e => set({ ...data, medecin: e.target.value })} placeholder="Dr. XYZ" style={inputStyle} />
        </div>
      </div>
    </div>
  );
}

