function ProtocoleDT({ data, set }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
      {[1, 2, 3, 4].map(num => (
        <div key={num} style={{ display: 'flex', alignItems: 'center', gap: '16px', border: '1px solid #eaebef', padding: '12px', borderRadius: '8px' }}>
          <div style={{ width: '80px', fontWeight: 800, color: '#0056ff' }}>{num}° Dose</div>
          <div style={{ flex: 1 }}>
            {num > 1 && (
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                <span style={{ fontSize: '13px', color: '#8a94a6', fontWeight: 600 }}>Après</span>
                <input type="number" value={data[`apresMois${num}`] || ''} onChange={e => set({ ...data, [`apresMois${num}`]: e.target.value })} placeholder="X" style={{ width: '60px', padding: '6px', borderRadius: '4px', border: '1px solid #eaebef', outline: 'none' }} />
                <span style={{ fontSize: '13px', color: '#8a94a6', fontWeight: 600 }}>mois</span>
              </div>
            )}
            <input type="date" value={data[`dose${num}`] || ''} onChange={e => set({ ...data, [`dose${num}`]: e.target.value })} style={{ ...inputStyle, padding: '8px 12px' }} />
          </div>
        </div>
      ))}
      <div>
        <label style={labelStyle}>Le Médecin</label>
        <input value={data.medecin || ''} onChange={e => set({ ...data, medecin: e.target.value })} placeholder="Dr. XYZ" style={inputStyle} />
      </div>
    </div>
  );
}

// --- MAIN MODAL ---

function VaccinModal({ vaccination, patients, onClose, onSave }) {
  const [form, setForm] = useState(vaccination || { patientId: '', type: 'rage', protocoleData: { grade: 'Grade II' } });

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const setProtocole = (data) => set('protocoleData', data);

  const handleSubmit = async (e) => {
    e.preventDefault();
    // Simulate generic save mapping for now to keep app working while backend unmodded
    const payload = { ...form, statut: 'complete', vaccin: PROTOCOLES.find(p=>p.id === form.type)?.label, dateAdministration: new Date().toISOString() };
    if (vaccination?.id) {
      await api.updateVaccination(vaccination.id, payload);
    } else {
      await api.createVaccination(payload);
    }
    onSave();
  };

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(29, 33, 41, 0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: 'white', borderRadius: '16px', padding: '32px', width: '100%', maxWidth: '700px', boxShadow: '0 10px 40px rgba(0,0,0,0.1)', maxHeight: '90vh', overflowY: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <h2 style={{ fontFamily: 'Syne, sans-serif', fontSize: '20px', fontWeight: 800, color: '#1d2129' }}>{vaccination?.id ? 'Modifier le protocole' : 'Saisir un protocole officiel'}</h2>
          <button style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#8a94a6' }} onClick={onClose}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
            <div>
              <label style={labelStyle}>Patient *</label>
              <select required value={form.patientId} onChange={e => set('patientId', e.target.value)} style={inputStyle}>
                <option value="" disabled>-- Sélectionner le patient --</option>
                {patients.map(p => <option key={p.id} value={p.id}>{p.nom} {p.prenom}</option>)}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Type de Certificat (Protocole) *</label>
              <select required value={form.type} onChange={e => set('type', e.target.value)} style={{...inputStyle, background: '#ebf2ff', color: '#0056ff', fontWeight: 700, border: '1px solid #d4e3ff'}}>
                {PROTOCOLES.map(p => <option key={p.id} value={p.id}>{p.label}</option>)}
              </select>
            </div>
          </div>

          <div style={{ borderTop: '2px solid #f4f5f9', paddingTop: '24px' }}>
             {form.type === 'rage' && <ProtocoleRage data={form.protocoleData} set={setProtocole} />}
             {form.type === 'hepb' && <ProtocoleHepB data={form.protocoleData} set={setProtocole} />}
             {form.type === 'dt'   && <ProtocoleDT   data={form.protocoleData} set={setProtocole} />}
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', marginTop: '8px' }}>
            <button type="button" onClick={onClose} style={{ padding: '12px 24px', borderRadius: '50px', border: '1px solid #eaebef', background: 'white', fontWeight: 700, cursor: 'pointer', color: '#8a94a6' }}>Annuler</button>
            <button type="submit" style={{ padding: '12px 24px', borderRadius: '50px', border: 'none', background: '#0056ff', fontWeight: 700, cursor: 'pointer', color: 'white' }}>
              Enregistrer le Certificat
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

// --- LISTE PRINCIPALE ---

export default function Vaccinations({ selectedPatient, setSelectedPatient }) {
  const [vaccinations, setVaccinations] = useState([]);
  const [patients, setPatients] = useState([]);
  const [modal, setModal] = useState(null);
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    const [v, p] = await Promise.all([
      api.getVaccinations({}),
      api.getPatients()
    ]);
    setVaccinations(v);
    setPatients(p);
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const handleDelete = async (id) => {
    if (window.confirm('Supprimer ce certificat officiel ?')) {
      await api.deleteVaccination(id);
      load();
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '32px' }}>
        <div>
          <h1 style={{ fontFamily: 'Syne', fontSize: 26, fontWeight: 800, color: '#1d2129', marginBottom: 4 }}>Certificats & Protocoles</h1>
          <p style={{ color: '#8a94a6', fontSize: 14 }}>Registres officiels Anti-Rabique, Hépatite B et DT.</p>
        </div>
        <button onClick={() => setModal('create')} style={{ background: '#0056ff', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '50px', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', boxShadow: '0 4px 15px rgba(0,86,255,0.2)' }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2l-2 2 4 4 2-2-4-4z"></path><path d="M10 4L2 12l2 2-2 2 2 2 2-2 2 2 8-8-8-8z"></path><line x1="14" y1="10" x2="4" y2="20"></line></svg>
          Saisir un Registre
        </button>
      </div>

      <div className="card" style={{ border: 'none', padding: '24px', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40, color: '#8a94a6' }}>Chargement...</div>
        ) : vaccinations.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 20px', color: '#8a94a6', background: '#f4f5f9', borderRadius: '12px' }}>
            Aucun certificat enregistré.
          </div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
              <thead>
                <tr style={{ color: '#8a94a6', borderBottom: '1px solid #eaebef' }}>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Date Initiale</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Patient</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Type de Registre</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Détails Profil</th>
                  <th style={{ padding: '16px 8px', textAlign: 'right' }}></th>
                </tr>
              </thead>
              <tbody>
                {vaccinations.map((v, i) => {
                  return (
                    <tr key={v.id} style={{ borderBottom: i < vaccinations.length-1 ? '1px solid #eaebef' : 'none' }}>
                      <td style={{ padding: '16px 8px', fontWeight: 600, fontSize: 13, color: '#1d2129' }}>
                        {new Date(v.dateAdministration || Date.now()).toLocaleDateString('fr-FR')}
                      </td>

                      <td style={{ padding: '16px 8px', fontWeight: 800, fontSize: 14, color: '#1d2129' }}>
                        {v.patient}
                      </td>

                      <td style={{ padding: '16px 8px' }}>
                        <span style={{ fontWeight: 800, color: '#0056ff', background: '#ebf2ff', padding: '4px 10px', borderRadius: '6px', fontSize: '13px' }}>
                          {v.type === 'rage' ? 'Anti-Rabique' : v.type === 'hepb' ? 'Hépatite B' : v.type === 'dt' ? 'DT' : v.vaccin}
                        </span>
                      </td>

                      <td style={{ padding: '16px 8px', color: '#8a94a6', fontSize: 13 }}>
                        {v.type === 'rage' ? `Grade: ${v.protocoleData?.grade}` : v.type === 'hepb' ? `Schéma: ${v.protocoleData?.schema}` : 'Formulaire Officiel'}
                      </td>

                      <td style={{ padding: '16px 8px', textAlign: 'right' }}>
                        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                          <button onClick={() => setModal(v)} style={{ background: '#f4f5f9', border: '1px solid #eaebef', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#8a94a6' }} title="Voir le certificat">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
                          </button>
                          <button onClick={() => handleDelete(v.id)} style={{ background: '#fce7f3', border: '1px solid #fbcfe8', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#ec4899' }} title="Supprimer">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"></path></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {modal && (
        <VaccinModal
          vaccination={modal === 'create' ? null : modal}
          patients={patients}
          onClose={() => setModal(null)}
          onSave={() => { setModal(null); load(); }}
        />
      )}
    </div>
  );
}
